import React from 'react';

const InterventionQueue = ({ interventions, onInterventionClick }) => {

  const getUrgencyClass = (window) => {
    if (window?.includes('Immediate') || window?.includes('Urgent')) return 'urgent';
    if (window?.includes('High')) return 'high';
    return 'watch';
  };

  const getUrgencyColor = (window) => {
    if (window?.includes('Immediate') || window?.includes('Urgent')) return '#EF4444';
    if (window?.includes('High')) return '#F59E0B';
    return '#3B82F6';
  };

  return (
    <div className="intervention-queue">
      {interventions.slice(0, 10).map((intervention, index) => (
        <div 
          key={index}
          className={`risk-item ${getUrgencyClass(intervention.Response_Window)}`}
          onClick={() => onInterventionClick(intervention.Protocol_ID)}
        >
          <div className="risk-type">{intervention.Response_Window} · {intervention.Responsible_Owner}</div>
          <div className="risk-title">{intervention.Product} — {intervention.Country}</div>
          <div className="risk-meta">{intervention.Action_Description}</div>
          <div className="risk-amount" style={{ color: getUrgencyColor(intervention.Response_Window) }}>
            ${intervention.revenue_recovered_millions.toFixed(1)}M recoverable
          </div>
        </div>
      ))}

      {interventions.length === 0 && (
        <div className="empty-state">
          <p>No interventions required</p>
          <p className="text-muted">All submissions on track</p>
        </div>
      )}
    </div>
  );
};

export default InterventionQueue;
